/* HealingMart Calculator Sound Adapter v1.4.0
 * Uses Healing Mart Audio Manager v1.2.0 only.
 */
(function (w, d) {
  "use strict";

  var MANAGER_URL = "https://healingmart.github.io/hm-mini-game-sound-pack/js/hm-audio-manager.v1.js?v=1.2.0";
  var SOUND_BASE = "https://healingmart.github.io/hm-mini-game-sound-pack/sfx/core/v1/";
  var STORE_KEY = "hm-mini-game-sound-enabled";
  var loadPromise = null;
  var cooldowns = Object.create(null);
  var USED_SOUNDS = ["ui-tap","ui-select","ui-confirm","ui-error","ui-back","ui-disabled","toggle-on","toggle-off","success"];

  try {
    if (w.localStorage.getItem(STORE_KEY) == null) w.localStorage.setItem(STORE_KEY, "0");
  } catch (_) {}

  function managerReady() {
    return !!(w.HMAudio && typeof w.HMAudio.init === "function");
  }

  function ensureManager() {
    if (managerReady()) {
      w.HMAudio.init({ baseUrl: SOUND_BASE, volume: 0.68 });
      return Promise.resolve(w.HMAudio);
    }
    if (loadPromise) return loadPromise;
    loadPromise = new Promise(function (resolve) {
      var s = d.createElement("script");
      s.src = MANAGER_URL;
      s.onload = function () {
        if (managerReady()) {
          w.HMAudio.init({ baseUrl: SOUND_BASE, volume: 0.68 });
          resolve(w.HMAudio);
        } else resolve(null);
      };
      s.onerror = function () { resolve(null); };
      d.head.appendChild(s);
    });
    return loadPromise;
  }

  function isEnabled() {
    try { return w.localStorage.getItem(STORE_KEY) === "1"; } catch (_) { return false; }
  }

  async function setEnabled(next) {
    var manager = await ensureManager();
    try { w.localStorage.setItem(STORE_KEY, next ? "1" : "0"); } catch (_) {}
    if (manager && manager.setEnabled) manager.setEnabled(!!next);
    if (next && manager && manager.preload) manager.preload(USED_SOUNDS).catch(function () {});
    return !!next;
  }

  function canPlay(name, delay) {
    var now = Date.now();
    var last = cooldowns[name] || 0;
    if (now - last < (delay || 100)) return false;
    cooldowns[name] = now;
    return true;
  }

  async function play(name, options) {
    if (!isEnabled()) return false;
    options = options || {};
    if (!canPlay(name, options.cooldown || 100)) return false;
    var manager = await ensureManager();
    if (!manager || !manager.play) return false;
    try { return await manager.play(name, { volume: options.volume == null ? 0.42 : options.volume }); }
    catch (_) { return false; }
  }

  function soundIcon(on) {
    return on
      ? '<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 10v4h4l5 4V6l-5 4H4z"></path><path d="M16 9c1.2 1.4 1.2 4.6 0 6M18.5 6.5c3 3 3 8 0 11"></path></svg>'
      : '<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 10v4h4l5 4V6l-5 4H4z"></path><path d="m17 9 4 6M21 9l-4 6"></path></svg>';
  }

  function mount(root) {
    if (!root || root.dataset.hmCalcSoundMounted === "true") return;
    root.dataset.hmCalcSoundMounted = "true";

    ensureManager().then(function (manager) {
      if (manager && manager.setEnabled) manager.setEnabled(isEnabled());
    });

    var toolbar = d.createElement("div");
    toolbar.className = "hm-calc-utility-bar";
    var toggle = d.createElement("button");
    toggle.type = "button";
    toggle.className = "hm-calc-sound-toggle";

    function paint() {
      var on = isEnabled();
      toggle.setAttribute("aria-pressed", on ? "true" : "false");
      toggle.setAttribute("title", on ? "계산기 소리 끄기" : "계산기 소리 켜기");
      toggle.innerHTML = soundIcon(on) + '<span>소리 ' + (on ? "켬" : "끔") + "</span>";
    }

    paint();
    toggle.addEventListener("click", async function () {
      if (isEnabled()) {
        await play("toggle-off", { volume: 0.40, cooldown: 120 });
        setTimeout(function () { setEnabled(false); paint(); }, 120);
      } else {
        await setEnabled(true);
        await play("toggle-on", { volume: 0.40, cooldown: 120 });
        paint();
      }
    });
    toolbar.appendChild(toggle);
    root.insertBefore(toolbar, root.firstChild);

    root.addEventListener("click", function (event) {
      var button = event.target.closest("button");
      if (!button || button === toggle) return;
      if (button.closest(".hm-calc-share-inline")) {
        play("ui-confirm", { volume: 0.34 });
        return;
      }
      if (!button.classList.contains("hm-calc-btn")) return;
      if (button.disabled) {
        play("ui-disabled", { volume: 0.34 });
        return;
      }
      if (button.classList.contains("secondary")) {
        play("ui-back", { volume: 0.34 });
        return;
      }
      setTimeout(function () {
        var msg = root.querySelector(".hm-calc-message:not([hidden])");
        var result = root.querySelector(".hm-calc-result:not([hidden])");
        if (msg && msg.textContent.trim()) play("ui-error", { volume: 0.36 });
        else if (result) play("success", { volume: 0.50, cooldown: 180 });
        else play("ui-confirm", { volume: 0.36 });
      }, 0);
    });
  }

  w.HM_CALC_SOUND = { mount: mount, play: play, setEnabled: setEnabled, isEnabled: isEnabled, usedSounds: USED_SOUNDS.slice() };
})(window, document);
